form:Form.form:Scripts:
function val_f_ingreso(Me)
{
	if (Me.TypedValue() != null){
		if (Ctrl('f_ingreso').TypedValue() >= NowDate()){					
			Me.SetError('La fecha de Ingreso debe ser anterior a Hoy');
			return false;
		}
		else return true;			
	}
	else return true;
}

function val_f_egreso(Me)
{
	if (Me.TypedValue() != null)
	{
		if (Me.TypedValue() > NowDate())
		{
			Me.SetError('La fecha de Egreso debe ser anterior o igual a Hoy');
			return false;
		}						
		else 
		if (Ctrl('f_ingreso').TypedValue() != null){
			if (Ctrl('f_ingreso').TypedValue() >= Me.TypedValue()){
				Me.SetError('La fecha de Egreso debe ser posterior a la fecha de Ingreso');
				return false;
			}
			else return true;
		}
		else return true;
	}
	else return true;
}
